 *
 * Effects:
 *   Returns the number of prime factors of the input "n", counted with
 *   multiplicity, using an iterative implementation.
 */
static unsigned int
count_factors(unsigned int n)
{
	unsigned int count = 0;
	unsigned int d;

	assert(n > 1);
	for (d = 2; d * d <= n; d++) {
		while (n % d == 0) {
			count++;
			n /= d;
		}
	}
	if (n > 1)
		count++;
	return (count);
}

